/**
 * Validates the return URL to prevent open redirect vulnerabilities.
 * Only allows relative paths or URLs from allowed domains.
 * 
 * WARNING: Using req.query.return_url directly in res.redirect() without
 * validation is an Open Redirect vulnerability (CWE-601). An attacker could
 * craft a malicious link like:
 *   /auth/callback?return_url=https://evil-site.com/phishing
 * which would redirect authenticated users to a malicious site.
 */
function validateReturnUrl(returnUrl) {
  const defaultUrl = '/';

  if (!returnUrl || typeof returnUrl !== 'string') {
    return defaultUrl;
  }

  // Allow only relative URLs (starting with / but not //)
  if (returnUrl.startsWith('/') && !returnUrl.startsWith('//')) {
    // Additional check: no protocol injection
    try {
      const parsed = new URL(returnUrl, 'http://localhost');
      if (parsed.hostname === 'localhost') {
        return returnUrl;
      }
    } catch {
      return defaultUrl;
    }
  }

  // For absolute URLs, check against allowed domains
  const allowedDomains = [
    'yourdomain.com',
    'www.yourdomain.com',
    'app.yourdomain.com'
  ];

  try {
    const parsed = new URL(returnUrl);
    if (allowedDomains.includes(parsed.hostname) && parsed.protocol === 'https:') {
      return returnUrl;
    }
  } catch {
    // Invalid URL
  }

  return defaultUrl;
}

